 16→    @State private var viewModel: AIChatViewModel
 17→    @State private var showClearConfirmation = false
 18→
 19→    init(resolver: Resolver) {
 20→        self.resolver = resolver
 21→        self._viewModel = State(initialValue: AIChatViewModel(resolver: resolver))
