141→    // MARK: - Messages List
142→
143→    private var messagesListView: some View {
144→        ScrollViewReader { proxy in
145→            ScrollView {
146→                LazyVStack(spacing: FitTodaySpacing.sm) {
147→                    ForEach(viewModel.messages) { message in
148→                        messageBubble(for: message)
149→                            .id(message.id)
150→                    }
151→
152→                    if viewModel.isLoading {
153→                        HStack {
154→                            ProgressView()
155→                                .tint(FitTodayColor.brandPrimary)
156→                            Text("fitorb.thinking".localized)
157→                                .font(FitTodayFont.ui(size: 14, weight: .medium))
158→                                .foregroundStyle(FitTodayColor.textSecondary)
159→                            Spacer()
160→                        }
161→                        .padding(.horizontal, FitTodaySpacing.md)
162→                        .id("loading")
163→                    } else if viewModel.isTyping {
164→                        HStack(spacing: 4) {
165→                            ForEach(0..<3, id: \.self) { i in
