 11→struct OptimizedPaywallView: View {
 12→    @Environment(\.dismiss) private var dismiss
 13→    @Environment(AppRouter.self) private var router
 14→    @State private var storeService: StoreKitService
 15→
 16→    @State private var selectedProduct: Product?
 17→    @State private var errorMessage: ErrorMessage?
 18→
 19→    private let onPurchaseSuccess: () -> Void
 20→    private let onDismiss: () -> Void
 21→
 22→    init(
 23→        storeService: StoreKitService,
 24→        onPurchaseSuccess: @escaping () -> Void = {},
 25→        onDismiss: @escaping () -> Void = {}
 26→    ) {
 27→        _storeService = State(initialValue: storeService)
 28→        self.onPurchaseSuccess = onPurchaseSuccess
 29→        self.onDismiss = onDismiss
 30→    }
 31→
 32→    var body: some View {
 33→        NavigationStack {
 34→            ScrollView {
 35→                VStack(spacing: FitTodaySpacing.xl) {
 36→                    PaywallHeroSection()
 37→
 38→                    LifetimeValueHighlight()
 39→
 40→                    lifetimePriceSection
 41→
 42→                    FeatureComparisonTable()
 43→
 44→                    PaywallCTASection(
 45→                        selectedProduct: selectedProduct,
 46→                        isPurchasing: storeService.purchaseState == .purchasing,
 47→                        onPurchase: { Task { await purchaseSelectedProduct() } },
 48→                        onRestore: { Task { await restorePurchases() } }
 49→                    )
 50→
 51→                    LegalSection()
 52→                }
 53→                .padding()
 54→            }
 55→            .background(
 56→                ZStack {
 57→                    FitTodayColor.background
 58→                    RetroGridPattern(lineColor: FitTodayColor.gridLine.opacity(0.2), spacing: 40)
 59→                }
 60→                .ignoresSafeArea()
 61→            )
 62→            .navigationBarTitleDisplayMode(.inline)
 63→            .toolbar {
 64→                ToolbarItem(placement: .cancellationAction) {
 65→                    Button {
 66→                        onDismiss()
 67→                        dismiss()
 68→                    } label: {
 69→                        Image(systemName: "xmark.circle.fill")
 70→                            .foregroundStyle(FitTodayColor.textSecondary)
 71→                    }
 72→                }
 73→            }
 74→            .task {
 75→                await storeService.loadProducts()
 76→                selectedProduct = storeService.lifetimeProduct
 77→            }
 78→            .errorToast(errorMessage: $errorMessage)
 79→            .onChange(of: storeService.purchaseState) { _, newState in
 80→                handlePurchaseStateChange(newState)
 81→            }
 82→        }
 83→    }
 84→
 85→    // MARK: - Lifetime Price Section
 86→
 87→    private var lifetimePriceSection: some View {
 88→        VStack(spacing: FitTodaySpacing.sm) {
 89→            if let product = storeService.lifetimeProduct {
 90→                VStack(spacing: FitTodaySpacing.xs) {
 91→                    Text(product.displayPrice)
 92→                        .font(FitTodayFont.display(size: 40, weight: .extraBold))
 93→                        .foregroundStyle(FitTodayColor.textPrimary)
 94→
 95→                    Text("pagamento único")
 96→                        .font(FitTodayFont.ui(size: 15, weight: .medium))
 97→                        .foregroundStyle(FitTodayColor.textSecondary)
 98→                }
 99→                .padding(FitTodaySpacing.lg)
100→                .frame(maxWidth: .infinity)
101→                .background(
102→                    RoundedRectangle(cornerRadius: FitTodayRadius.lg)
103→                        .fill(FitTodayColor.brandPrimary.opacity(0.08))
104→                )
105→                .overlay(
106→                    RoundedRectangle(cornerRadius: FitTodayRadius.lg)
107→                        .stroke(FitTodayColor.brandPrimary.opacity(0.3), lineWidth: 2)
108→                )
109→                .techCornerBorders(color: FitTodayColor.neonCyan, length: 16, thickness: 2)
110→            } else if storeService.purchaseState == .loading {
111→                ProgressView()
112→                    .frame(height: 100)
113→            }
114→        }
115→    }
116→
117→    // MARK: - Actions
118→
119→    private func purchaseSelectedProduct() async {
120→        guard let product = selectedProduct else { return }
121→        let success = await storeService.purchase(product)
122→        if success {
123→            onPurchaseSuccess()
124→            dismiss()
125→        }
126→    }
127→
128→    private func restorePurchases() async {
129→        let restored = await storeService.restorePurchases()
130→        if restored {
131→            onPurchaseSuccess()
132→            dismiss()
133→        } else if storeService.purchaseState != .failed("") {
134→            errorMessage = ErrorMessage(title: "Restaurar Compras", message: "Nenhuma compra encontrada para restaurar.")
135→        }
136→    }
137→
138→    private func handlePurchaseStateChange(_ state: StoreKitService.PurchaseState) {
139→        if case .failed(let message) = state {
140→            errorMessage = ErrorMessage(title: "Erro", message: message)
141→        }
142→    }
143→}
