  5→
  6→import Foundation
  7→import StoreKit
  8→
  9→/// Serviço responsável por interagir com StoreKit 2 para compra única (non-consumable).
 10→@MainActor
 11→@Observable final class StoreKitService {
 12→    private(set) var products: [Product] = []
 13→    private(set) var purchaseState: PurchaseState = .idle
 14→    private(set) var hasProAccess = false
 15→
 16→    private nonisolated(unsafe) var transactionListener: Task<Void, Never>?
 17→    private let logger: (String) -> Void
 18→
 19→    enum PurchaseState: Equatable {
 20→        case idle
 21→        case loading
 22→        case purchasing
 23→        case success
 24→        case failed(String)
 25→        case cancelled
 26→    }
 27→
 28→    init(logger: @escaping (String) -> Void = { print("[StoreKit]", $0) }) {
 29→        self.logger = logger
 30→        startTransactionListener()
 31→    }
 32→
 33→    deinit {
 34→        transactionListener?.cancel()
 35→    }
 36→
 37→    // MARK: - Fetch Products
 38→
 39→    func loadProducts() async {
 40→        purchaseState = .loading
 41→        do {
 42→            let storeProducts = try await Product.products(for: StoreKitProductID.allProducts)
 43→            products = storeProducts
 44→            purchaseState = .idle
 45→            logger("Loaded \(products.count) products")
 46→        } catch {
 47→            logger("Failed to load products: \(error.localizedDescription)")
 48→            purchaseState = .failed("Não foi possível carregar os produtos.")
 49→        }
 50→    }
 51→
 52→    // MARK: - Purchase
 53→
 54→    func purchase(_ product: Product) async -> Bool {
 55→        purchaseState = .purchasing
 56→        logger("Initiating purchase for \(product.id)")
 57→
 58→        do {
 59→            let result = try await product.purchase()
 60→
 61→            switch result {
 62→            case .success(let verification):
 63→                let transaction = try checkVerified(verification)
 64→                await transaction.finish()
 65→                await refreshPurchaseStatus()
 66→                purchaseState = .success
 67→                logger("Purchase successful for \(product.id)")
 68→                return true
 69→
 70→            case .userCancelled:
 71→                purchaseState = .cancelled
 72→                logger("User cancelled purchase")
 73→                return false
 74→
 75→            case .pending:
 76→                purchaseState = .idle
 77→                logger("Purchase pending approval")
 78→                return false
 79→
 80→            @unknown default:
 81→                purchaseState = .idle
 82→                logger("Unknown purchase result")
 83→                return false
 84→            }
 85→        } catch {
 86→            purchaseState = .failed(error.localizedDescription)
 87→            logger("Purchase failed: \(error.localizedDescription)")
 88→            return false
 89→        }
 90→    }
 91→
 92→    // MARK: - Restore Purchases
 93→
 94→    func restorePurchases() async -> Bool {
 95→        purchaseState = .loading
 96→        logger("Restoring purchases...")
 97→
 98→        do {
 99→            try await AppStore.sync()
100→            await refreshPurchaseStatus()
101→            purchaseState = hasProAccess ? .success : .idle
102→            logger("Restore completed. Has Pro: \(hasProAccess)")
103→            return hasProAccess
104→        } catch {
105→            purchaseState = .failed("Não foi possível restaurar compras.")
106→            logger("Restore failed: \(error.localizedDescription)")
107→            return false
108→        }
109→    }
110→
111→    // MARK: - Check Purchase Status
112→
113→    func refreshPurchaseStatus() async {
114→        var isActive = false
115→
116→        for await verificationResult in Transaction.currentEntitlements {
117→            switch verificationResult {
118→            case .verified(let transaction):
119→                if StoreKitProductID.allProducts.contains(transaction.productID) {
120→                    if transaction.revocationDate == nil {
121→                        isActive = true
122→                        logger("Active entitlement found: \(transaction.productID)")
123→                    }
124→                }
125→            case .unverified(_, let error):
126→                logger("Unverified transaction: \(error.localizedDescription)")
127→            }
128→        }
129→
130→        hasProAccess = isActive
131→    }
132→
133→    // MARK: - Get Current Entitlement Info
134→
135→    func getCurrentEntitlement() async -> ProEntitlement {
136→        for await verificationResult in Transaction.currentEntitlements {
137→            if case .verified(let transaction) = verificationResult {
138→                if StoreKitProductID.allProducts.contains(transaction.productID) {
139→                    if transaction.revocationDate == nil {
140→                        return ProEntitlement(
141→                            isPro: true,
142→                            source: .storeKit,
143→                            expirationDate: nil
144→                        )
145→                    }
146→                }
147→            }
148→        }
149→
150→        return .free
151→    }
152→
153→    // MARK: - Transaction Listener
154→
155→    private func startTransactionListener() {
156→        transactionListener = Task.detached { [weak self] in
157→            for await result in Transaction.updates {
158→                await self?.handleTransactionUpdate(result)
159→            }
160→        }
161→    }
162→
163→    private func handleTransactionUpdate(_ result: VerificationResult<Transaction>) async {
164→        switch result {
165→        case .verified(let transaction):
166→            logger("Transaction update received: \(transaction.productID)")
167→            await transaction.finish()
168→            await refreshPurchaseStatus()
169→        case .unverified(_, let error):
170→            logger("Unverified transaction update: \(error.localizedDescription)")
171→        }
172→    }
173→
174→    // MARK: - Helpers
175→
176→    private func checkVerified<T>(_ result: VerificationResult<T>) throws -> T {
177→        switch result {
178→        case .unverified(_, let error):
179→            throw error
180→        case .verified(let safe):
181→            return safe
182→        }
183→    }
184→
185→    // MARK: - Product Accessors
186→
187→    var lifetimeProduct: Product? {
188→        products.first { $0.id == StoreKitProductID.proLifetime }
189→    }
190→}
