14→        self.modelContainer = modelContainer
15→    }
16→
17→    private func context() -> ModelContext {
18→        ModelContext(modelContainer)
19→    }
20→
21→    func loadMessages(limit: Int) async throws -> [AIChatMessage] {
22→        var descriptor = FetchDescriptor<SDChatMessage>(
23→            sortBy: [SortDescriptor(\.timestamp, order: .forward)]
24→        )
25→        descriptor.fetchLimit = limit
26→        let models = try context().fetch(descriptor)
27→        return models.compactMap(ChatMessageMapper.toDomain)
28→    }
29→
30→    func saveMessage(_ message: AIChatMessage) async throws {
31→        let ctx = context()
32→        ctx.insert(ChatMessageMapper.toModel(message))
33→        try ctx.save()
34→    }
35→
36→    func clearHistory() async throws {
37→        let ctx = context()
38→        let descriptor = FetchDescriptor<SDChatMessage>()
39→        let all = try ctx.fetch(descriptor)
40→        for model in all {
41→            ctx.delete(model)
42→        }
43→        try ctx.save()
44→    }
45→
46→    func messageCount() async throws -> Int {
47→        let descriptor = FetchDescriptor<SDChatMessage>()
48→        return try context().fetchCount(descriptor)
49→    }
50→}
