 8→struct ChatMessageMapper {
 9→    static func toDomain(_ model: SDChatMessage) -> AIChatMessage? {
10→        guard let role = AIChatMessage.Role(rawValue: model.roleRaw) else { return nil }
11→        return AIChatMessage(id: model.id, role: role, content: model.content, timestamp: model.timestamp)
12→    }
13→
14→    static func toModel(_ message: AIChatMessage) -> SDChatMessage {
15→        SDChatMessage(id: message.id, roleRaw: message.role.rawValue, content: message.content, timestamp: message.timestamp)
16→    }
17→}
