//
//  AIChatViewModel.swift
//  FitToday
//
//  ViewModel for the AI FitOrb chat feature.
//

import Foundation
import Swinject

@MainActor
@Observable
final class AIChatViewModel: ErrorPresenting {

    // MARK: - Properties

    var messages: [AIChatMessage] = []
    var inputText: String = ""
    var isLoading: Bool = false
    var isTyping: Bool = false
    var errorMessage: ErrorMessage?
    private(set) var quickActions: [String] = []

    // MARK: - Private

    private let resolver: Resolver
    private let chatRepository: ChatRepository?
    private let featureGating: FeatureGating?
    private let usageTracker: AIUsageTracking?
    private let profileRepository: UserProfileRepository?
    private let statsRepository: UserStatsRepository?
    private var typingTask: Task<Void, Never>?
    private var _cachedChatService: AIChatService?

    /// Creates on-demand so API key saved after launch takes effect.
    private var chatService: AIChatService? {
        if let cached = _cachedChatService { return cached }
        guard let client = NewOpenAIClient.fromUserKey(),
              let profileRepo = resolver.resolve(UserProfileRepository.self),
              let statsRepo = resolver.resolve(UserStatsRepository.self),
              let historyRepo = resolver.resolve(WorkoutHistoryRepository.self)
        else { return nil }
        let service = AIChatService(
            client: client,
            profileRepository: profileRepo,
            statsRepository: statsRepo,
            historyRepository: historyRepo
        )
        _cachedChatService = service
        return service
    }

    // MARK: - Initialization

    init(resolver: Resolver) {
        self.resolver = resolver
        self.chatRepository = resolver.resolve(ChatRepository.self)
        self.featureGating = resolver.resolve(FeatureGating.self)
        self.usageTracker = resolver.resolve(AIUsageTracking.self)
        self.profileRepository = resolver.resolve(UserProfileRepository.self)
        self.statsRepository = resolver.resolve(UserStatsRepository.self)
        self.quickActions = Self.defaultQuickActions
    }

    // MARK: - Computed

    var isChatAvailable: Bool {
        chatService != nil
    }

    // MARK: - Actions

    func loadHistory() async {
        guard let repo = chatRepository else { return }
        do {
            messages = try await repo.loadMessages(limit: 50)
        } catch {
            handleError(error)
        }
        await loadQuickActions()
    }

    func sendMessage() {
        let text = inputText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !text.isEmpty, !isLoading, !isTyping else { return }

        guard chatService != nil else {
            errorMessage = ErrorMessage(
                title: "error.openai.not_configured.title".localized,
                message: "fitorb.error_no_api_key".localized,
                action: .dismiss
            )
            return
        }

        // Cancel any ongoing typing animation
        typingTask?.cancel()
        typingTask = nil

        let userMessage = AIChatMessage(role: .user, content: text)
        messages.append(userMessage)
        inputText = ""
        isLoading = true
        errorMessage = nil

        Task {
            // Check message limit for free users
            if let gating = featureGating {
                let access = await gating.checkAccess(to: .aiChat)
                guard access.isAllowed else {
                    isLoading = false
                    // Remove the user message we just appended
                    if messages.last?.role == .user {
                        messages.removeLast()
                    }
                    handleError(DomainError.chatMessageLimitReached)
                    return
                }
            }

            // Save user message
            try? await chatRepository?.saveMessage(userMessage)

            do {
                let response = try await chatService!.sendMessage(text, history: messages)

                // Register chat usage
                await usageTracker?.registerChatUsage()

                // Animate typing effect
                await animateTyping(response: response)
            } catch {
                handleError(error)
            }
            isLoading = false
        }
    }

    func clearHistory() async {
        typingTask?.cancel()
        typingTask = nil
        isTyping = false
        messages.removeAll()
        try? await chatRepository?.clearHistory()
        await chatService?.invalidatePromptCache()
        await loadQuickActions()
    }

    // MARK: - Typing Animation

    private func animateTyping(response: String) async {
        // Create assistant message with empty content
        let messageId = UUID()
        let placeholder = AIChatMessage(id: messageId, role: .assistant, content: "")
        messages.append(placeholder)
        isLoading = false
        isTyping = true

        let chunkSize = 5
        var currentIndex = response.startIndex

        typingTask = Task { [weak self] in
            while currentIndex < response.endIndex && !Task.isCancelled {
                let nextIndex = response.index(currentIndex, offsetBy: chunkSize, limitedBy: response.endIndex) ?? response.endIndex
                let partialContent = String(response[response.startIndex..<nextIndex])
                currentIndex = nextIndex

                await MainActor.run {
                    guard let self else { return }
                    // Replace last message with updated content
                    if let lastIndex = self.messages.lastIndex(where: { $0.id == messageId }) {
                        self.messages[lastIndex] = AIChatMessage(
                            id: messageId,
                            role: .assistant,
                            content: partialContent,
                            timestamp: placeholder.timestamp
                        )
                    }
                }

                try? await Task.sleep(nanoseconds: 15_000_000) // 15ms
            }

            // Save final message after animation
            let finalMessage = AIChatMessage(
                id: messageId,
                role: .assistant,
                content: response,
                timestamp: placeholder.timestamp
            )

            await MainActor.run { [weak self] in
                guard let self else { return }
                if let lastIndex = self.messages.lastIndex(where: { $0.id == messageId }) {
                    self.messages[lastIndex] = finalMessage
                }
                self.isTyping = false
            }

            try? await self?.chatRepository?.saveMessage(finalMessage)
        }
    }

    // MARK: - Quick Actions

    private static var defaultQuickActions: [String] {
        [
            "fitorb.quick.plan_workout".localized,
            "fitorb.quick.suggest_exercises".localized,
            "fitorb.quick.warmup".localized,
            "fitorb.quick.recovery".localized
        ]
    }

    private func loadQuickActions() async {
        var actions: [String] = []

        let profile = try? await profileRepository?.loadProfile()
        let stats = try? await statsRepository?.getCurrentStats()

        let hour = Calendar.current.component(.hour, from: Date())

        // Time-based suggestions
        if hour < 12 {
            actions.append("fitorb.quick.morning_warmup".localized)
        } else if hour >= 20 {
            actions.append("fitorb.quick.evening_stretch".localized)
        }

        // Workout status today
        if let lastDate = stats?.lastWorkoutDate,
           Calendar.current.isDateInToday(lastDate) {
            actions.append("fitorb.quick.recovery".localized)
        } else {
            actions.append("fitorb.quick.suggest_today".localized)
        }

        // Goal-specific suggestions
        if let goal = profile?.mainGoal {
            switch goal {
            case .hypertrophy:
                actions.append("fitorb.quick.muscle_tips".localized)
            case .weightLoss:
                actions.append("fitorb.quick.fat_burn_tips".localized)
            case .endurance:
                actions.append("fitorb.quick.endurance_tips".localized)
            case .conditioning, .performance:
                actions.append("fitorb.quick.performance_tips".localized)
            }
        }

        // Always include a generic option
        actions.append("fitorb.quick.plan_workout".localized)

        // Limit to 4 chips
        quickActions = Array(actions.prefix(4))

        // Fallback if empty
        if quickActions.isEmpty {
            quickActions = Self.defaultQuickActions
        }
    }
}

//
//  EntitlementPolicy.swift
//  FitToday
//
//  Política centralizada de acesso a features baseada no entitlement.
//

import Foundation

// MARK: - Feature Enum

/// Features que requerem verificação de acesso
enum ProFeature: String, CaseIterable {
    // Treinos IA
    case aiWorkoutGeneration = "ai_workout_generation"
    case aiExerciseSubstitution = "ai_exercise_substitution"

    // Tracking avançado
    case unlimitedHistory = "unlimited_history"
    case advancedDOMSAdjustment = "advanced_doms_adjustment"

    // Biblioteca
    case premiumPrograms = "premium_programs"

    // Configurações
    case customizableSettings = "customizable_settings"

    // Personal Trainer
    case personalTrainer = "personal_trainer"
    case trainerWorkouts = "trainer_workouts"

    // Social
    case simultaneousChallenges = "simultaneous_challenges"

    // AI Chat
    case aiChat = "ai_chat"

    var displayName: String {
        switch self {
        case .aiWorkoutGeneration: return "Treinos personalizados por IA"
        case .aiExerciseSubstitution: return "Substituição inteligente de exercícios"
        case .unlimitedHistory: return "Histórico ilimitado"
        case .advancedDOMSAdjustment: return "Ajuste por dor muscular"
        case .premiumPrograms: return "Programas premium"
        case .customizableSettings: return "Configurações avançadas"
        case .personalTrainer: return "Personal Trainer"
        case .trainerWorkouts: return "Treinos do Personal"
        case .simultaneousChallenges: return "Desafios simultâneos ilimitados"
        case .aiChat: return "Assistente IA FitOrb"
        }
    }
}

// MARK: - Access Result

/// Resultado da verificação de acesso
enum FeatureAccessResult {
    case allowed
    case limitReached(remaining: Int, limit: Int)
    case requiresPro(feature: ProFeature)
    case trialExpired
    case featureDisabled(reason: String)

    var isAllowed: Bool {
        if case .allowed = self { return true }
        return false
    }

    /// Indicates if the result is due to a disabled feature flag.
    var isFeatureDisabled: Bool {
        if case .featureDisabled = self { return true }
        return false
    }

    var message: String {
        switch self {
        case .allowed:
            return ""
        case .limitReached(_, let limit):
            return "Você atingiu o limite de \(limit) usos. Desbloqueie o Pro para mais."
        case .requiresPro(let feature):
            return "\(feature.displayName) é um recurso Pro. Desbloqueie o Pro para acessar."
        case .trialExpired:
            return "Seu período de teste terminou. Desbloqueie o Pro para continuar."
        case .featureDisabled(let reason):
            return reason
        }
    }
}

// MARK: - Entitlement Policy

/// Política centralizada para verificação de acesso a features
struct EntitlementPolicy {

    // MARK: - Limites

    /// Número de treinos IA por semana para usuários Free
    static let freeAIWorkoutsPerWeek = 1

    /// Número de treinos IA por dia para usuários Pro
    static let proAIWorkoutsPerDay = 2

    /// Dias de histórico para usuários Free
    static let freeHistoryDaysLimit = 7

    /// Número máximo de desafios simultâneos para Free
    static let freeChallengesLimit = 5

    /// Numero de mensagens AI chat por dia para usuarios Free
    static let freeAIChatMessagesPerDay = 5

    // MARK: - Verificação de Acesso

    /// Verifica se o usuário pode acessar uma feature
    /// - Parameters:
    ///   - feature: Feature a ser verificada
    ///   - entitlement: Entitlement atual do usuário
    ///   - usageCount: Uso atual (semanal para Free AI, diário para Pro AI, contagem ativa para desafios)
    /// - Returns: Resultado da verificação
    static func canAccess(
        _ feature: ProFeature,
        entitlement: ProEntitlement,
        usageCount: Int = 0
    ) -> FeatureAccessResult {

        // Pro tem acesso a tudo (com limites diários em IA)
        if entitlement.isPro {
            if let expiration = entitlement.expirationDate, expiration < Date() {
                return .trialExpired
            }

            switch feature {
            case .aiWorkoutGeneration:
                if usageCount >= proAIWorkoutsPerDay {
                    return .limitReached(remaining: 0, limit: proAIWorkoutsPerDay)
                }
                return .allowed
            case .aiChat:
                return .allowed
            default:
                return .allowed
            }
        }

        // Verificar features específicas para Free
        switch feature {
        case .aiWorkoutGeneration:
            if usageCount >= freeAIWorkoutsPerWeek {
                return .limitReached(remaining: 0, limit: freeAIWorkoutsPerWeek)
            }
            return .allowed

        case .simultaneousChallenges:
            if usageCount >= freeChallengesLimit {
                return .limitReached(remaining: 0, limit: freeChallengesLimit)
            }
            return .allowed

        case .aiChat:
            if usageCount >= freeAIChatMessagesPerDay {
                return .limitReached(remaining: 0, limit: freeAIChatMessagesPerDay)
            }
            return .allowed

        case .aiExerciseSubstitution,
             .unlimitedHistory,
             .advancedDOMSAdjustment,
             .premiumPrograms,
             .customizableSettings,
             .personalTrainer,
             .trainerWorkouts:
            return .requiresPro(feature: feature)
        }
    }

    /// Verifica se uma feature é totalmente bloqueada para Free
    static func isProOnly(_ feature: ProFeature) -> Bool {
        switch feature {
        case .aiWorkoutGeneration, .simultaneousChallenges, .aiChat:
            return false // Free tem acesso limitado
        case .aiExerciseSubstitution,
             .unlimitedHistory,
             .advancedDOMSAdjustment,
             .premiumPrograms,
             .customizableSettings,
             .personalTrainer,
             .trainerWorkouts:
            return true
        }
    }

    /// Retorna o limite de uso para uma feature
    static func usageLimit(for feature: ProFeature, entitlement: ProEntitlement) -> (limit: Int, period: String)? {
        switch feature {
        case .aiWorkoutGeneration:
            if entitlement.isPro {
                return (proAIWorkoutsPerDay, "dia")
            } else {
                return (freeAIWorkoutsPerWeek, "semana")
            }
        case .simultaneousChallenges:
            if entitlement.isPro {
                return nil // ilimitado
            } else {
                return (freeChallengesLimit, "simultâneos")
            }
        case .aiChat:
            if entitlement.isPro {
                return nil // ilimitado
            } else {
                return (freeAIChatMessagesPerDay, "dia")
            }
        default:
            return nil
        }
    }

    // MARK: - Helpers para UI

    /// Retorna lista de features que são Pro-only para exibição
    static var proOnlyFeatures: [ProFeature] {
        ProFeature.allCases.filter { isProOnly($0) }
    }

    /// Retorna lista de features com limites para Free
    static var limitedFreeFeatures: [(feature: ProFeature, freeLimit: String, proLimit: String)] {
        [
            (.aiWorkoutGeneration, "1/semana", "2/dia"),
            (.simultaneousChallenges, "5", "∞"),
            (.aiChat, "5/dia", "ilimitado")
        ]
    }
}

// MARK: - Convenience Extensions

extension ProEntitlement {
    /// Verifica acesso a uma feature usando a policy centralizada
    func canAccess(_ feature: ProFeature, usageCount: Int = 0) -> FeatureAccessResult {
        EntitlementPolicy.canAccess(feature, entitlement: self, usageCount: usageCount)
    }

    /// Verifica se tem acesso a uma feature (simplificado)
    func hasAccess(to feature: ProFeature) -> Bool {
        canAccess(feature).isAllowed
    }
}

